// Helpers
// ---------------------------------------------------------------------
func buildInspectionsURLString(filter models.InspectionFilter) string {
	params := []string{}
	if filter.TransportID.Set {
		params = append(params, "transport_id="+strconv.Itoa(int(filter.TransportID.Value)))
	}
	if filter.Status.Set && filter.Status.Value != "" {
		params = append(params, "status="+string(filter.Status.Value))
	}
	if filter.InspectionDateFrom.Set && !filter.InspectionDateFrom.Value.IsZero() {
		params = append(params, "inspection_from="+filter.InspectionDateFrom.Value.Format("2006-01-02"))
	}
	if filter.InspectionDateTo.Set && !filter.InspectionDateTo.Value.IsZero() {
		params = append(params, "inspection_to="+filter.InspectionDateTo.Value.Format("2006-01-02"))
	}
	if filter.InspectionExpirationFrom.Set && !filter.InspectionExpirationFrom.Value.IsZero() {
		params = append(params, "expiration_from="+filter.InspectionExpirationFrom.Value.Format("2006-01-02"))
	}
	if filter.InspectionExpirationTo.Set && !filter.InspectionExpirationTo.Value.IsZero() {
		params = append(params, "expiration_to="+filter.InspectionExpirationTo.Value.Format("2006-01-02"))
	}
	if filter.SortBy.Set {
		params = append(params, "sort="+filter.SortBy.Value)
	}
	if filter.SortOrder.Set {
		params = append(params, "order="+filter.SortOrder.Value)
	}
	return strings.Join(params, "&")
}

func buildInspectionsURL(baseQuery string, page int) string {
	if baseQuery == "" {
		return fmt.Sprintf("/inspections?page=%d", page)
	}
	return fmt.Sprintf("/inspections?%s&page=%d", baseQuery, page)
}

